BEGIN;
CREATE TEMP TABLE _ref_map (id uuid PRIMARY KEY, old_ref text, new_ref text);
UPDATE public.products p SET ref = 'TMP-' || p.id::text;
UPDATE public.products p SET ref = m.new_ref, sku = m.new_ref, updated_at = now() FROM _ref_map m WHERE p.id = m.id;
DELETE FROM public.product_ref_aliases;
    SELECT upper(m.old_ref), m.new_ref, m.id
    FROM _ref_map m
    WHERE upper(m.old_ref) IS DISTINCT FROM m.new_ref;
COMMIT;